<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PML4_PHYS_ADDR</span></span>
